import java.util.*;
import org.owasp.encoder.Encode;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        String welcomeMessage = "Hello, " + Encode.forHtml(userInput) + "! Welcome to our website!";

        // Properly handling user input by encoding it before embedding it in the HTML response
        System.out.println("<html><body>");
        System.out.println("<h1>" + welcomeMessage + "</h1>");
        System.out.println("</body></html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
